	// ------------------------------
	// Retrieves detailed records for M_DEP4 report
	// ------------------------------
	public ModelAndView getM_DEP4currentDtl(String reportId, String fromdate, String todate, String currency,
			String dtltype, Pageable pageable, String Filter, String type, String version, HttpServletRequest req1,
			Model md) {

		int pageSize = pageable != null ? pageable.getPageSize() : 10;
		int currentPage = pageable != null ? pageable.getPageNumber() : 0;
		int totalPages = 0;

		ModelAndView mv = new ModelAndView();

		String userid = (String) req1.getSession().getAttribute("USERID");
		System.out.println("User Id Maker and Checker: " + userid);
		String role = userProfileRep.getUserRole(userid);
		md.addAttribute("role", role);
		System.out.println("Role: " + role);

//	Session hs = sessionFactory.getCurrentSession();

		try {
			Date parsedDate = null;
			if (todate != null && !todate.isEmpty()) {
				parsedDate = dateformat.parse(todate);
			}

			String rowId = null;
			String columnId = null;

			// ✅ Split filter string into rowId & columnId
			if (Filter != null && Filter.contains(",")) {
				String[] parts = Filter.split(",");
				if (parts.length >= 2) {
					rowId = parts[0];
					columnId = parts[1];
				}
			}

			if ("ARCHIVAL".equals(type) && version != null) {
				// 🔹 Archival branch
				List<M_DEP4_Archival_Detail_Entity> T1Dt1;
				if (rowId != null && columnId != null) {
					T1Dt1 = jdbcTemplate.query(
							"SELECT * FROM BRRS_M_DEP4_ARCHIVALTABLE_DETAIL WHERE REPORT_LABEL = ? AND REPORT_ADDL_CRITERIA_1 = ? AND REPORT_DATE = ? AND DATA_ENTRY_VERSION = ?",
							new Object[] { rowId, columnId, parsedDate, version },
							new BeanPropertyRowMapper<>(M_DEP4_Archival_Detail_Entity.class));
				} else {
					T1Dt1 = jdbcTemplate.query(
							"SELECT * FROM BRRS_M_DEP4_ARCHIVALTABLE_DETAIL WHERE REPORT_DATE = ? AND DATA_ENTRY_VERSION = ?",
							new Object[] { parsedDate, version },
							new BeanPropertyRowMapper<>(M_DEP4_Archival_Detail_Entity.class));
				}

				mv.addObject("reportdetails", T1Dt1);
				mv.addObject("reportmaster12", T1Dt1);
				System.out.println("ARCHIVAL COUNT: " + (T1Dt1 != null ? T1Dt1.size() : 0));

			} else {
				// 🔹 Current branch
				List<M_DEP4_Detail_Entity> T1Dt1;
				if (rowId != null && columnId != null) {
					T1Dt1 = jdbcTemplate.query(
							"SELECT * FROM BRRS_M_DEP4_DETAILTABLE WHERE REPORT_LABEL = ? AND REPORT_ADDL_CRITERIA_1 = ? AND REPORT_DATE = ?",
							new Object[] { rowId, columnId, parsedDate },
							new BeanPropertyRowMapper<>(M_DEP4_Detail_Entity.class));
				} else {
					T1Dt1 = jdbcTemplate.query("SELECT * FROM BRRS_M_DEP4_DETAILTABLE WHERE REPORT_DATE = ?",
							new Object[] { parsedDate }, new BeanPropertyRowMapper<>(M_DEP4_Detail_Entity.class));
					totalPages = jdbcTemplate.queryForObject(
							"SELECT COUNT(*) FROM BRRS_M_DEP4_DETAILTABLE WHERE REPORT_DATE = ?",
							new Object[] { parsedDate }, Integer.class);
					mv.addObject("pagination", "YES");
				}

				mv.addObject("reportdetails", T1Dt1);
				mv.addObject("reportmaster12", T1Dt1);
				System.out.println("LISTCOUNT: " + (T1Dt1 != null ? T1Dt1.size() : 0));
			}

		} catch (ParseException e) {
			e.printStackTrace();
			mv.addObject("errorMessage", "Invalid date format: " + todate);
		} catch (Exception e) {
			e.printStackTrace();
			mv.addObject("errorMessage", "Unexpected error: " + e.getMessage());
		}

		// ✅ Common attributes
		mv.setViewName("BRRS/M_DEP4");
		mv.addObject("displaymode", "Details");
		mv.addObject("currentPage", currentPage);
		System.out.println("totalPages: " + (int) Math.ceil((double) totalPages / 100));
		mv.addObject("totalPages", (int) Math.ceil((double) totalPages / 100));
		mv.addObject("reportsflag", "reportsflag");
		mv.addObject("menu", reportId);

		return mv;
	}

	// ------------------------------
	// Updates M_DEP4 summary report part 1 fields
	// ------------------------------
	public void updateReport1(M_DEP4_Summary_Entity1 entity1) {
		System.out.println("Report Date: " + entity1.getReportDate());
		if (entity1.getReportDate() == null) {
			throw new RuntimeException("REPORT_DATE is NULL");
		}

		String checkSql = "SELECT COUNT(*) FROM BRRS_M_DEP4_SUMMARYTABLE1 WHERE REPORT_DATE = ?";
		Integer count = jdbcTemplate.queryForObject(checkSql, new Object[] { entity1.getReportDate() }, Integer.class);
		if (count == null || count == 0) {
			throw new RuntimeException("Record not found for REPORT_DATE: " + entity1.getReportDate());
		}

		StringBuilder updateSql = new StringBuilder("UPDATE BRRS_M_DEP4_SUMMARYTABLE1 SET ");
		List<Object> params = new ArrayList<>();

		for (int i = 10; i <= 100; i++) {
			String prefix = "R" + i + "_";
			String[] fields = { "interest_rate", "amount", "total_deposit", "percentage_total_deposit" };

			for (String field : fields) {
				String getterName = "get" + prefix + field;
				try {
					java.lang.reflect.Method getter = M_DEP4_Summary_Entity1.class.getMethod(getterName);
					Object newValue = getter.invoke(entity1);

					updateSql.append(prefix).append(field).append(" = ?, ");
					params.add(newValue);
				} catch (NoSuchMethodException e) {
					continue;
				} catch (Exception e) {
					throw new RuntimeException("Error while reading field " + getterName, e);
				}
			}
		}

		if (params.isEmpty()) {
			return;
		}
		updateSql.setLength(updateSql.length() - 2);
		updateSql.append(" WHERE REPORT_DATE = ?");
		params.add(entity1.getReportDate());

		jdbcTemplate.update(updateSql.toString(), params.toArray());
	}

