//////////////////////////////////////////RESUBMISSION///////////////////////////////////////////////////////////////////
/// Report Date | Report Version | Domain
/// RESUB VIEW

	// ------------------------------
	// Retrieves version list for M_DEP4 resubmission
	// ------------------------------
	public List<Object[]> getM_DEP4Resub() {
		List<Object[]> resubList = new ArrayList<>();
		try {
			List<M_DEP4_Archival_Summary_Entity1> latestArchivalList = jdbcTemplate.query(
					"SELECT * FROM BRRS_M_DEP4_ARCHIVALTABLE_SUMMARY1 WHERE REPORT_VERSION IS NOT NULL ORDER BY REPORT_VERSION ASC",
					new BeanPropertyRowMapper<>(M_DEP4_Archival_Summary_Entity1.class));

			if (latestArchivalList != null && !latestArchivalList.isEmpty()) {
				for (M_DEP4_Archival_Summary_Entity1 entity : latestArchivalList) {
					resubList.add(new Object[] { entity.getReportDate(), entity.getReportVersion() });
				}
				System.out.println("Fetched " + resubList.size() + " record(s)");
			} else {
				System.out.println("No archival data found.");
			}

		} catch (Exception e) {
			System.err.println("Error fetching M_dep4 Resub data: " + e.getMessage());
			e.printStackTrace();
		}
		return resubList;
	}

//Archival View
	// ------------------------------
	// Retrieves version list for M_DEP4 archival
	// ------------------------------
	public List<Object[]> getM_DEP4Archival() {

		List<Object[]> archivalList = new ArrayList<>();

		try {

			// Fetch data from Repository 1
			List<M_DEP4_Archival_Summary_Entity1> repoData1 = jdbcTemplate.query(
					"SELECT * FROM BRRS_M_DEP4_ARCHIVALTABLE_SUMMARY1 WHERE REPORT_VERSION IS NOT NULL ORDER BY REPORT_VERSION ASC",
					new BeanPropertyRowMapper<>(M_DEP4_Archival_Summary_Entity1.class));

			if (repoData1 != null && !repoData1.isEmpty()) {

				for (M_DEP4_Archival_Summary_Entity1 entity : repoData1) {

					Object[] row = new Object[] { entity.getReportDate(), entity.getReportVersion(),
							entity.getReportResubDate() };

					archivalList.add(row);
				}

				System.out.println("Fetched " + repoData1.size() + " archival records from Repo1");

				M_DEP4_Archival_Summary_Entity1 first = repoData1.get(0);
				System.out.println("Latest archival version (Repo1): " + first.getReportVersion());

			} else {
				System.out.println("No archival data found in Repo1.");
			}

			// Fetch data from Repository 2
			List<M_DEP4_Archival_Summary_Entity2> repoData2 = jdbcTemplate.query(
					"SELECT * FROM BRRS_M_DEP4_ARCHIVALTABLE_SUMMARY2 WHERE REPORT_VERSION IS NOT NULL ORDER BY REPORT_VERSION ASC",
					new BeanPropertyRowMapper<>(M_DEP4_Archival_Summary_Entity2.class));

			if (repoData2 != null && !repoData2.isEmpty()) {

				for (M_DEP4_Archival_Summary_Entity2 entity : repoData2) {

					Object[] row = new Object[] { entity.getReportDate(), entity.getReportVersion(),
							entity.getReportResubDate() };

					archivalList.add(row);
				}

				System.out.println("Fetched additional " + repoData2.size() + " archival records from Repo2");

				M_DEP4_Archival_Summary_Entity2 first = repoData2.get(0);
				System.out.println("Latest archival version (Repo2): " + first.getReportVersion());

			} else {
				System.out.println("No archival data found in Repo2.");
			}

			// Fetch data from Repository 3
			List<M_DEP4_Archival_Summary_Entity3> repoData3 = jdbcTemplate.query(
					"SELECT * FROM BRRS_M_DEP4_ARCHIVALTABLE_SUMMARY3 WHERE REPORT_VERSION IS NOT NULL ORDER BY REPORT_VERSION ASC",
					new BeanPropertyRowMapper<>(M_DEP4_Archival_Summary_Entity3.class));

			if (repoData3 != null && !repoData3.isEmpty()) {

				for (M_DEP4_Archival_Summary_Entity3 entity : repoData3) {

					Object[] row = new Object[] { entity.getReportDate(), entity.getReportVersion(),
							entity.getReportResubDate() };

					archivalList.add(row);
				}

				System.out.println("Fetched additional " + repoData3.size() + " archival records from Repo3");

				M_DEP4_Archival_Summary_Entity3 first = repoData3.get(0);
				System.out.println("Latest archival version (Repo3): " + first.getReportVersion());

			} else {
				System.out.println("No archival data found in Repo3.");
			}

		} catch (Exception e) {

			System.err.println("Error fetching M_DEP4 Archival data: " + e.getMessage());
			e.printStackTrace();
		}

		return archivalList;
	}

